SELECT b.id, b.title, b.isbn, b.published_year, b.description
FROM books b


		b.title ILIKE '%' || #{title} || '%'


		AND EXISTS (
			SELECT 1 FROM book_categories bc
			WHERE bc.book_id = b.id AND bc.category_id = #{categoryId}
		)


ORDER BY b.id
LIMIT #{limit} OFFSET #{offset}

SELECT id, title, isbn, published_year, description
FROM books
WHERE id = #{id}

SELECT COUNT(*)
FROM books
WHERE isbn = #{isbn}

	AND id != #{excludeId}

mapper.update:
UPDATE books
SET title = #{title}, isbn = #{isbn}, published_year = #{publishedYear}, description = #{description}
WHERE id = #{id}
